-- 6. Margate × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'margate',
  'Social media is arguably more important in Margate than any other town in Kent. The entire regeneration story has been amplified through Instagram, with Turner Contemporary, Harbour Arm sunsets, The Old Town''s curated shopfronts, and Dreamland''s retro aesthetic generating millions of social media impressions annually. Visitors discover Margate businesses through Instagram before they ever set foot in the town. DFL residents share their finds obsessively, creating organic amplification that no advertising budget can replicate. Yet many Margate businesses have social profiles that were set up hastily and fail to capitalise on this extraordinary organic reach. A stunning Old Town shop with an Instagram bio that says nothing useful. A Harbour Arm venue with a Facebook page showing last year''s menu. A Cliftonville business with no Instagram presence at all, invisible to the audience that drives Margate''s economy. We set up social media profiles that transform your Margate business into a destination that people discover, share, and return to.',
  'Margate''s social media ecosystem is visually driven and geographically concentrated. Instagram is the dominant discovery platform, with Turner Contemporary, The Old Town, Harbour Arm, and Dreamland functioning as self-curating content generators. Facebook remains important for the established Thanet community and local event promotion. TikTok is growing among younger visitors and Dreamland-adjacent audiences. The tight geography of Margate''s creative quarter means location tags and local hashtags drive significant discovery, with Margate consistently trending among London lifestyle and travel audiences.',
  'Social media quality in Margate''s creative quarter is some of the highest in Kent, with several Old Town businesses maintaining Instagram accounts that rival professional lifestyle publications. However, this raises the bar for everyone: a poorly curated profile looks worse next to strong competitors than it would in a town with universally low social standards. Beyond The Old Town, many Margate and Cliftonville businesses have underdeveloped social profiles that miss the organic discovery traffic flowing through the town.',
  'We set up Margate social media profiles to the standard the town''s creative community expects. Every profile receives professional imagery that reflects your brand and the specific Margate context you operate in, optimised bios that drive action rather than just describe, and a content strategy framework that capitalises on the town''s natural visual appeal and social media culture. We ensure your profiles are discoverable through the location tags, hashtags, and connections that drive Margate''s social economy.',
  '{"population": 62000, "thanet_population": 141000, "key_areas": ["The Old Town", "Harbour Arm", "Dreamland", "Cliftonville", "Marine Terrace"], "social_landscape": "Instagram-dominant discovery platform, strong visual culture"}',
  '[{"title": "Margate businesses with Instagram profiles that underperform the town''s visual potential", "description": "Margate is one of the most Instagrammable towns in England, yet many local businesses have profiles with inconsistent imagery, missing bio links, and no strategic content approach. They are surrounded by extraordinary visual content opportunities near Turner Contemporary, Harbour Arm, and The Old Town but fail to capitalise on any of them."}, {"title": "Invisible to the London audience that drives Margate''s discovery economy", "description": "When a London visitor searches the Margate location tag on Instagram to plan their day trip, businesses without a strong Instagram presence simply do not exist. For a town where social media discovery drives a significant portion of visitor spending, being invisible on Instagram is the equivalent of having no shopfront."}, {"title": "Inconsistent profiles undermining brand credibility across Margate platforms", "description": "A Margate business has different logos across Instagram, Facebook, and Google. Their bio says one thing on Facebook and another on Instagram. The overall impression is a business that does not pay attention to detail, a fatal flaw in a town where creative attention to detail is the cultural currency."}]',
  '[{"title": "Instagram-optimised profile setup for Margate''s visual discovery economy", "description": "We build your Instagram presence to capitalise on Margate''s extraordinary visual culture. Professional profile imagery, a bio that converts browsers into followers and customers, strategic highlights showcasing your offerings, and a visual grid strategy that makes your profile feel curated and intentional alongside The Old Town''s best accounts."}, {"title": "Multi-platform consistency across Margate''s social landscape", "description": "We set up Facebook, Instagram, Google Business Profile, and where appropriate TikTok with perfectly consistent branding, messaging, and business information. Whether a Thanet local finds you on Facebook or a London visitor discovers you through Instagram, the experience is cohesive and professional."}, {"title": "Margate hashtag and location strategy for maximum discovery", "description": "We research and implement the specific hashtag combinations and location tags that drive discovery in Margate''s social ecosystem. From Turner Contemporary to Harbour Arm to Dreamland, we ensure your content is discoverable through the channels that Margate''s visitor and resident audiences actively browse."}]',
  '[{"question": "How important is Instagram for a Margate business?", "answer": "For consumer-facing businesses in Margate, Instagram is arguably the most important marketing channel. The town''s visual culture and London visitor audience make it the primary discovery platform. Businesses in The Old Town, on Harbour Arm, and near Dreamland that invest in strong Instagram presence consistently outperform those that do not."}, {"question": "Can you set up TikTok for my Margate business?", "answer": "Yes. TikTok is growing in relevance for Margate businesses, particularly those targeting younger visitors and the Dreamland audience. We set up optimised profiles and provide content frameworks suited to the platform''s format, leveraging Margate''s inherently shareable visual environment."}, {"question": "How long does social media setup take for a Margate business?", "answer": "Complete social media setup across Instagram, Facebook, and Google Business Profile typically takes five to seven working days. This includes professional imagery, optimised profiles, branded templates, and a content strategy framework. TikTok setup adds two to three additional days if required."}, {"question": "Do I need professional photography for my Margate social media?", "answer": "High-quality imagery significantly impacts performance in Margate''s visually sophisticated social environment. We can arrange professional photography as part of the setup or work with your existing images if they meet quality standards. We also provide smartphone photography guidelines so you can maintain visual quality in your ongoing content."}]',
  'trust'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
